  ('promotion-bd450684-moex-00041', 'promotion-bd450684', 'promotion-bd450684-moex-112-7aee8e3e', 'sub-promotion-bd450684-02', NULL, 'essay', '甲廠商參與乙機關「拍擊器雷管及零組件」之招標，該採購案之採購規
範第 26 點訂有：「本案所列各項數量為二年期間之預估數量，在契約金
額範圍內本機關得視實際需要叫貨並調整各項數量。」及第 27 點「本
機關不保證於契約期間將每項數量及本案契約金額全部叫完。」甲廠商
除依投標須知填妥「財物採購案廠商規格檢點／審查單」及相關證明文
件外，另自行檢附乙紙公文併附於投標文件內，主旨載以：「本公司參與
投標貴機關採購案，有關規格詳述如說明，請鑒核」，說明欄謂：「採購
規範第 26 點貴機關可調整各項數量部分，各項數如欲增加叫貨超過原
預估數量，應先與廠商確認是否可供應」及「採購規範第 27 點貴機關
不保證於契約期間將各項數量及本案契約金額全部叫完部分，因本案產
品有其特殊性，本公司有權於契約到期前半年，按本案所列各項數量 7
成請求貴機關執行採購，貴機關不得拒絕。」請試分析乙機關於審標時，
對於甲廠商所提「財物採購案廠商規格檢點／審查單」、相關證明文件，
及自行檢附之乙紙公文，應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:58+00:00", "source_pdf_sha1": "3a001e12004e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "127", "s": "0516", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "廉政"}'::jsonb, NULL),
